class Solution:
    def findMaximumLength(self, nums):
        n = len(nums)
        best = 0

        def rec(i, prev_sum, count):
            nonlocal best
            if i == n:
                if count > best:
                    best = count
                return
            s = 0
            for j in range(i, n):
                s += nums[j]
                if s >= prev_sum:
                    rec(j + 1, s, count + 1)

        rec(0, 0, 0)
        return best

