class Solution:
    def findMaximumLength(self, nums):
        n = len(nums)
        P = [0] * (n + 1)
        for i in range(n):
            P[i + 1] = P[i] + nums[i]
        dp_f = [0] * (n + 1)
        dp_g = [0] * (n + 1)
        for i in range(1, n + 1):
            best_len = -1
            best_sum = None
            for j in range(i):
                seg = P[i] - P[j]
                if seg >= dp_g[j]:
                    cand = dp_f[j] + 1
                    if cand > best_len or (cand == best_len and seg < best_sum):
                        best_len = cand
                        best_sum = seg
            dp_f[i] = best_len
            dp_g[i] = best_sum
        return dp_f[n]

