var findMaximumLength = function(nums) {
    const n = nums.length;
    const P = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) P[i + 1] = P[i] + nums[i];
    const dpF = new Array(n + 1).fill(0);
    const dpG = new Array(n + 1).fill(0);
    for (let i = 1; i <= n; i++) {
        let bestLen = -1;
        let bestSum = Infinity;
        for (let j = 0; j < i; j++) {
            const seg = P[i] - P[j];
            if (seg >= dpG[j]) {
                const cand = dpF[j] + 1;
                if (cand > bestLen || (cand === bestLen && seg < bestSum)) {
                    bestLen = cand;
                    bestSum = seg;
                }
            }
        }
        dpF[i] = bestLen;
        dpG[i] = bestSum;
    }
    return dpF[n];
};
